    # T' = (0,-1): x = s; y = -1 + w, w(w-1+2s... ) solve G: (w-1)^2+2s(w-1)+(w-1)
    # -s^3 = 0 -> w^2 - w + 2sw - 2s - s^3 = 0 => w = (2s + s^3 + w^2 + 2sw... )
