    # w = (2s + s^3 + w^2)/(1 - 2s)?? derive: G(x,-1+w) = (-1+w)^2 + 2x(-1+w)
    # + (-1+w) - x^3 = 1 - 2w + w^2 - 2x + 2xw - 1 + w - x^3 = w^2 + w(2x - 1)
    # - 2x - x^3. So w = (2x + x^3 - w^2)/(2x - 1)*(-1)... w(2x-1) = 2x + x^3 - w^2
    # => w = (2x + x^3 - w^2)/(2x - 1).
