MONS = [(p, q) for p in range(-_sage_const_3 , _sage_const_5 ) for q in range(_sage_const_0 , _sage_const_2 )]


def omega0_val_and_series(pl):
    xs, ys = E0S[pl]
    dx = xs.derivative()
    den = _sage_const_2 *ys + _sage_const_2 *xs + _sage_const_1 
    return dx/den


def gate_dimension(j):
    rows = []
    ncols = _sage_const_3 *len(MONS)
    for pl in ('T', 'Tp', 'O'):
        xs, ys = E0S[pl]
        w0 = omega0_val_and_series(pl)
        tb = TB[pl]
        for ub in UB[pl]:
            Fu = _sage_const_3 *ub**_sage_const_2  + xs
            pref = (tb**j) * w0 / Fu
            # eta = g * pref must be regular: expansion coefficients of negative
            # orders vanish.  Collect condition rows down to order -1.
            colblocks = []
            minv = _sage_const_10 **_sage_const_9 
            series_list = []
            for i in range(_sage_const_3 ):
                for (p, q) in MONS:
                    ser = (xs**p) * (ys**q) * (ub**i) * pref
                    series_list.append(ser)
                    minv = min(minv, ser.valuation())
            if minv >= _sage_const_0 :
                continue
            for order in range(minv, _sage_const_0 ):
                row = [ser[order] for ser in series_list]
                rows.append(row)
    M = matrix(F, rows)
    return ncols - M.rank()


